@media (min-width: 769px) and (max-width: 1024px) {
    .glass-card {
        border-radius: 14px;
        margin: 12px;
    }
}

/* 桌面 */
@media (min-width: 1025px) {
    .glass-card {
        border-radius: 16px;
        margin: 16px;
    }
}
```

