        // 游戏状态
        let state = {
            currentChapter: 0,
            favorability: 50,
            hasLearnedSpell: false
        };

        // DOM 元素
        const storyText = document.getElementById('storyText');
        const cursor = document.getElementById('cursor');
        const optionsContainer = document.getElementById('optionsContainer');
        const optionsDiv = document.getElementById('options');
        const chapterTitle = document.getElementById('chapterTitle');
        const chatPanel = document.getElementById('chatPanel');
        const chatMessages = document.getElementById('chatMessages');
        const chatInput = document.getElementById('chatInput');
        const chatSend = document.getElementById('chatSend');
        const settingsModal = document.getElementById('settingsModal');

        // 打字机效果
        let typeTimeout;
        function typeText(text, callback) {
            storyText.innerHTML = '';
            cursor.style.display = 'inline';
            let index = 0;

            function type() {
                if (index < text.length) {
                    storyText.textContent += text.charAt(index);
                    index++;
                    document.getElementById('storyContent').scrollTop = document.getElementById('storyContent').scrollHeight;
                    typeTimeout = setTimeout(type, 30);
                } else {
                    cursor.style.display = 'none';
                    if (callback) callback();
                }
            }
            type();
        }

        // 显示章节
        function showChapter(chapterIndex) {
            if (chapterIndex === -1) {
                // 重新开始
                state = { currentChapter: 0, favorability: 50, hasLearnedSpell: false };
                localStorage.removeItem('laoshan_game_state');
            } else {
                state.currentChapter = chapterIndex;
                saveState();
            }

            const chapter = gameData.chapters[chapterIndex === -1 ? 0 : chapterIndex];
            chapterTitle.textContent = chapter.title;

            optionsDiv.innerHTML = '';
            optionsContainer.style.display = 'none';

            typeText(chapter.content, () => {
                if (chapter.options.length > 0) {
                    optionsContainer.style.display = 'block';
                    chapter.options.forEach((opt, i) => {
                        const btn = document.createElement('button');
                        btn.className = 'option-btn';
                        btn.textContent = opt.text;
                        btn.onclick = () => selectOption(opt);
                        optionsDiv.appendChild(btn);
                    });
                }
            });
        }

        // 选择选项
        function selectOption(option) {
            state.favorability += option.favorChange;
            state.favorability = Math.max(0, Math.min(100, state.favorability));

            if (option.next === 7 || option.next === 8) {
                state.hasLearnedSpell = true;
            }

            // 根据好感度决定结局
            let nextChapter = option.next;
            if (nextChapter === 7 && state.favorability < 30) {
                nextChapter = 8; // 变成好结局
            }

            showChapter(nextChapter);
        }

        // 保存状态
        function saveState() {
            localStorage.setItem('laoshan_game_state', JSON.stringify(state));
        }

        // 加载状态
        function loadState() {
            const saved = localStorage.getItem('laoshan_game_state');
            if (saved) {
                state = JSON.parse(saved);
            }
        }

        // API 配置
        let apiConfig = {
            baseUrl: '',
            apiKey: '',
            model: 'deepseek-chat'
        };

        function loadApiConfig() {
            const saved = localStorage.getItem('laoshan_api_config');
            if (saved) {
                apiConfig = JSON.parse(saved);
                document.getElementById('baseUrl').value = apiConfig.baseUrl;
                document.getElementById('apiKey').value = apiConfig.apiKey;
                document.getElementById('modelSelect').value = apiConfig.model;
            }
        }

        function saveApiConfig() {
            apiConfig.baseUrl = document.getElementById('baseUrl').value.trim();
            apiConfig.apiKey = document.getElementById('apiKey').value.trim();
            apiConfig.model = document.getElementById('modelSelect').value;
            localStorage.setItem('laoshan_api_config', JSON.stringify(apiConfig));
            updateConnectionStatus();
        }

        // 更新连接状态
        function updateConnectionStatus() {
            const status = apiConfig.apiKey ? 'connected' : 'disconnected';
            const statusEl = document.getElementById('connectionStatus');
            if (!statusEl) return;
            statusEl.className = 'connection-status ' + status;
            statusEl.textContent = status === 'connected' ? '已连接' : '未连接';
        }

        // 测试 API 连接
        async function testConnection() {
            const statusMsg = document.getElementById('statusMsg');
            const btn = document.getElementById('testConnection');

            if (!apiConfig.baseUrl || !apiConfig.apiKey) {
                statusMsg.className = 'status-msg error';
                statusMsg.textContent = '请填写 Base URL 和 API Key';
                return;
            }

            btn.disabled = true;
            btn.textContent = '测试中...';

            try {
                const response = await fetch(`${apiConfig.baseUrl}/v1/chat/completions`, {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${apiConfig.apiKey}`,
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({
                        model: apiConfig.model,
                        messages: [{ role: 'user', content: 'Hello' }],
                        max_tokens: 10
                    })
                });

                if (response.ok) {
                    statusMsg.className = 'status-msg success';
                    statusMsg.textContent = '✓ 连接成功！';
                } else {
                    const err = await response.json();
                    statusMsg.className = 'status-msg error';
                    statusMsg.textContent = '✗ 连接失败: ' + (err.error?.message || response.statusText);
                }
            } catch (e) {
                statusMsg.className = 'status-msg error';
                statusMsg.textContent = '✗ 连接失败: ' + e.message;
            }

            btn.disabled = false;
            btn.textContent = '测试连接';
        }

        // AI 对话
        let conversationHistory = [];

        async function sendMessage() {
            const message = chatInput.value.trim();
            if (!message) return;

            if (!apiConfig.apiKey) {
                alert('请先配置 API Key');
                openSettings();
                return;
            }

            // 添加玩家消息
            addChatMessage(message, 'player');
            chatInput.value = '';
            chatSend.disabled = true;

            // 添加 NPC 消息占位
            const npcMsgEl = addChatMessage('...', 'npc');

            try {
                const response = await fetch(`${apiConfig.baseUrl}/v1/chat/completions`, {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${apiConfig.apiKey}`,
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({
                        model: apiConfig.model,
                        messages: [
                            { role: 'system', content: '你是崂山道士，一位仙风道骨的道士。你学识渊博，精通道法，为人谦和但有时候会考验弟子的心性。请用古典文言的语气回答玩家的提问，可以适当引用道家经典。注意保持神秘感和仙风道骨的气质。玩家正在向你学习道法。' },
                            ...conversationHistory,
                            { role: 'user', content: message }
                        ],
                        stream: false
                    })
                });

                if (!response.ok) throw new Error('API 请求失败');

                const data = await response.json();
                const reply = data.choices[0].message.content;

                npcMsgEl.querySelector('.message-content').textContent = reply;
                conversationHistory.push({ role: 'user', content: message });
                conversationHistory.push({ role: 'assistant', content: reply });

            } catch (e) {
                npcMsgEl.querySelector('.message-content').textContent = '『贫道近日感应不灵，汝可稍后再试。』';
            }

            chatSend.disabled = false;
            chatMessages.scrollTop = chatMessages.scrollHeight;
        }

        function addChatMessage(content, type) {
            const div = document.createElement('div');
            div.className = `chat-message ${type}`;
            div.innerHTML = `<div class="message-content">${content}</div>`;
            chatMessages.appendChild(div);
            chatMessages.scrollTop = chatMessages.scrollHeight;
            return div;
        }

        // 打开/关闭设置
        function openSettings() {
            loadApiConfig();
            settingsModal.classList.add('active');
        }

        function closeSettings() {
            settingsModal.classList.remove('active');
        }

        // 切换聊天面板
        function toggleChat() {
            const isActive = chatPanel.classList.contains('active');
            if (isActive) {
                chatPanel.classList.remove('active');
            } else {
                chatPanel.classList.add('active');
                if (!apiConfig.apiKey) {
                    alert('请先配置 API Key');
                    openSettings();
                }
            }
        }

        // 事件绑定
        document.getElementById('settingsBtn').onclick = openSettings;
        document.getElementById('chatBtn').onclick = toggleChat;
        document.getElementById('restartBtn').onclick = () => showChapter(-1);
        document.getElementById('cancelSettings').onclick = closeSettings;
        document.getElementById('saveSettings').onclick = () => { saveApiConfig(); closeSettings(); };
        document.getElementById('testConnection').onclick = testConnection;
        chatSend.onclick = sendMessage;
        chatInput.onkeypress = (e) => { if (e.key === 'Enter') sendMessage(); };
        settingsModal.onclick = (e) => { if (e.target === settingsModal) closeSettings(); };

        // 初始化
        loadState();
        loadApiConfig();
        showChapter(state.currentChapter);
    </script>
